# ANTI-PATTERN: Processing tokens one-by-one without batching
class CricketCommentator_BadPattern:
    def __init__(self, model):
        self.model = model
        self.kv_cache = {}

    def generate_commentary(self, ball_sequence):
        """Process each ball independently—poor throughput"""
        commentary = []
        for ball_idx, ball in enumerate(ball_sequence):
            # Creating new batch for every ball wastes GPU
            output = self.model.forward(
                input_ids=ball,
                past_key_values=None  # No cache reuse!
            )
            commentary.append(output.logits[0, -1, :])
        return commentary

# BEST PRACTICE: Batch processing with KV cache
class CricketCommentator_BestPattern:
    def __init__(self, model, batch_size=32):
        self.model = model
        self.batch_size = batch_size
        self.kv_cache = {}

    def generate_commentary(self, ball_sequences):
        """Process balls in batches with cache reuse—optimal efficiency"""
        all_commentary = []

        for batch_start in range(0, len(ball_sequences), self.batch_size):
            batch_end = min(batch_start + self.batch_size, len(ball_sequences))
            batch = ball_sequences[batch_start:batch_end]

            # Initialize cache for new batch
            past_key_values = self._init_cache(batch.shape[0])

            for token_position in range(batch.shape[1]):
                # Process entire batch in single GPU call
                output = self.model.forward(
                    input_ids=batch[:, token_position:token_position+1],
                    past_key_values=past_key_values,
                    use_cache=True
                )
                # Update cache for next token prediction
                past_key_values = output.past_key_values
                all_commentary.append(output.logits[:, -1, :])

        return all_commentary

    def _init_cache(self, batch_size):
        """Initialize KV cache structure"""
        return None  # Model handles initialization

# PATTERN SELECTION: Match the innings
class CricketCommentator_Adaptive:
    def generate_commentary(
        self, 
        ball_sequences, 
        match_type="test",  # test (batch) vs t20 (streaming)
        hardware="gpu"  # gpu vs edge_device
    ):
        if match_type == "test" and hardware == "gpu":
            return CricketCommentator_BestPattern().generate_commentary(ball_sequences)
        elif match_type == "t20" and hardware == "gpu":
            return self._streaming_generate(ball_sequences)  # Interactive
        elif hardware == "edge_device":
            return self._quantized_generate(ball_sequences)  # Memory-constrained
        else:
            return self._rag_generate(ball_sequences)  # Knowledge-augmented
